sys_script_include.script:
var IncentNowUtils = Class.create();
IncentNowUtils.prototype = {
    initialize: function() {
    },

 getQuotaByUserBusinessUnit: function(userId) {
        // Always enforce active quotas
        var query = 'active=true';

        if (!userId) {
            return query;
        }

        var userGR = new GlideRecordSecure('x_ctans_incentnow_user_profile');
        if (userGR.get(userId) && userGR.business_unit) {
            query += '^business_unit=' + userGR.business_unit;
        }

        return query;
    },

	getUserByQuotaBusinessUnit: function(quotaId) {

    // Start with base condition (optional if you have active on user)
    var query = 'active=true';

    if (!quotaId) {
        return query;
    }

    var quotaGR = new GlideRecordSecure('x_ctans_incentnow_quota');
    if (quotaGR.get(quotaId) && quotaGR.business_unit) {
        query += '^business_unit=' + quotaGR.business_unit;
    }

    return query;
},

getUserByPlanBusinessUnit: function(planId) {

    // base query (optional if user has active)
    var query = 'active=true';

    if (!planId) {
        return query;
    }

    var planGR = new GlideRecordSecure('x_ctans_incentnow_plan');
    if (planGR.get(planId) && planGR.business_unit) {
        query += '^business_unit=' + planGR.business_unit;
    }

    return query;
},

getPlanByUserBusinessUnit: function(userId) {

    // base query (optional if plan has active)
    var query = 'active=true';

    if (!userId) {
        return query;
    }

    var userGR = new GlideRecordSecure('x_ctans_incentnow_user_profile');
    if (userGR.get(userId) && userGR.business_unit) {
        query += '^business_unit=' + userGR.business_unit;
    }

    return query;
},
    type: 'IncentNowUtils'
};
